import QRCode from"qrcode";import{formatError,formatInfo}from"../utils/formatters.js";export async function qr({fullArgs:e,from:t,sock:o}){if(e){await o.sendMessage(t,{text:"📱 *Generating QR code...*"});try{const a=`https://api.qrserver.com/v1/create-qr-code/?size=500x500&data=${encodeURIComponent(e)}`;await o.sendMessage(t,{image:{url:a},caption:`📱 *QR Code*\n📝 ${e}\n👑 AYOCODES`})}catch{try{const a=await QRCode.toBuffer(e,{width:500});await o.sendMessage(t,{image:a,caption:`📱 *QR Code*\n📝 ${e}\n👑 AYOCODES`})}catch{await o.sendMessage(t,{text:formatError("ERROR","Could not generate QR code.")})}}}else await o.sendMessage(t,{text:formatInfo("QR CODE","Usage: .qr <text or URL>\nExample: .qr https://github.com")})}